```

### src/data.ts
```typescript
import type { Product, Order } from "./types.js";

export const products: Product[] = [ /* 5 products */ ];
export const orders: Order[] = [ /* 2 orders */ ];
let nextOrderId = 3;
export function getNextOrderId(): number { return nextOrderId++; }
```

### src/routes/products.ts (current - business logic mixed in)
```typescript
import { Router } from "express";
import { products } from "../data.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;
  let filtered = [...products];
  if (category && typeof category === "string") {
    filtered = filtered.filter((p) => p.category === category);
  }
  if (minPrice && typeof minPrice === "string") {
    const min = parseFloat(minPrice);
    if (!isNaN(min)) { filtered = filtered.filter((p) => p.price >= min); }
  }
  if (maxPrice && typeof maxPrice === "string") {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) { filtered = filtered.filter((p) => p.price <= max); }
  }
  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice = filtered.length > 0
    ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length : 0;
  res.json({
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  });
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = products.find((p) => p.id === id);
  if (!product) { res.status(404).json({ error: "Product not found" }); return; }
  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;
  res.json({ ...product, isLowStock, inventoryValue });
});

// PATCH /products/:id/stock
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = products.find((p) => p.id === id);
  if (!product) { res.status(404).json({ error: "Product not found" }); return; }
  const { adjustment } = req.body as { adjustment: number };
  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" }); return;
  }
  const newStock = product.stock + adjustment;
  if (newStock < 0) { res.status(400).json({ error: "Insufficient stock" }); return; }
  product.stock = newStock;
  res.json({ ...product, isLowStock: product.stock < 10, inventoryValue: Math.round(product.price * product.stock * 100) / 100 });
});

export { router as productRouter };
```

### src/routes/orders.ts (current - business logic mixed in)
```typescript
import { Router } from "express";
import { orders, products, getNextOrderId } from "../data.js";
import type { CreateOrderInput, OrderItem } from "../types.js";

const router = Router();

// GET /orders
router.get("/orders", (req, res) => {
  const { userId, status } = req.query;
  let filtered = [...orders];
  if (userId && typeof userId === "string") {
    const uid = parseInt(userId, 10);
    if (!isNaN(uid)) { filtered = filtered.filter((o) => o.userId === uid); }
  }
  if (status && typeof status === "string") {
    filtered = filtered.filter((o) => o.status === status);
  }
  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);
  res.json({ orders: filtered, summary: { count: filtered.length, totalRevenue: Math.round(totalRevenue * 100) / 100 } });
});

// GET /orders/:id
router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = orders.find((o) => o.id === id);
  if (!order) { res.status(404).json({ error: "Order not found" }); return; }
  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return { ...item, productName: product?.name ?? "Unknown" };
  });
  res.json({ ...order, items: enrichedItems });
});

// POST /orders
router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    res.status(400).json({ error: "userId and items are required" }); return;
  }
  if (input.items.length === 0) {
    res.status(400).json({ error: "Order must have at least one item" }); return;
  }
  const orderItems: OrderItem[] = [];
  let total = 0;
  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) { res.status(400).json({ error: `Product ${item.productId} not found` }); return; }
    if (item.quantity <= 0) { res.status(400).json({ error: "Quantity must be positive" }); return; }
    if (product.stock < item.quantity) { res.status(400).json({ error: `Insufficient stock for ${product.name}` }); return; }
    product.stock -= item.quantity;
    const itemTotal = product.price * item.quantity;
    orderItems.push({ productId: product.id, quantity: item.quantity, price: product.price });
    total += itemTotal;
  }
  const order = {
    id: getNextOrderId(), userId: input.userId, items: orderItems,
    total: Math.round(total * 100) / 100, status: "pending" as const,
    createdAt: new Date().toISOString(),
  };
  orders.push(order);
  res.status(201).json(order);
});

// PATCH /orders/:id/status
router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = orders.find((o) => o.id === id);
  if (!order) { res.status(404).json({ error: "Order not found" }); return; }
  const { status } = req.body as { status: string };
  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    res.status(400).json({ error: `Invalid status. Must be one of: ${validStatuses.join(", ")}` }); return;
  }
  const transitions: Record<string, string[]> = {
    pending: ["confirmed"], confirmed: ["shipped"], shipped: ["delivered"], delivered: [],
  };
  if (!transitions[order.status]?.includes(status)) {
    res.status(400).json({ error: `Cannot transition from ${order.status} to ${status}` }); return;
  }
  order.status = status as typeof order.status;
  res.json(order);
});

export { router as orderRouter };
```

