import type { Product, Order, OrderItem, CreateOrderInput } from "../types.js";
import { ServiceError } from "./errors.js";

export interface OrderFilters {
  userId?: string;
  status?: string;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export function listOrders(
  filters: OrderFilters,
  orderList: Order[]
): OrderListResult {
  let filtered = [...orderList];

  if (filters.userId) {
    const uid = parseInt(filters.userId, 10);
    if (!isNaN(uid)) {
      filtered = filtered.filter((o) => o.userId === uid);
    }
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(
  id: number,
  orderList: Order[],
  productList: Product[]
): EnrichedOrder | null {
  const order = orderList.find((o) => o.id === id);
  if (!order) return null;

  const enrichedItems = order.items.map((item) => {
    const product = productList.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(
  input: CreateOrderInput,
  orderList: Order[],
  productList: Product[],
  nextId: () => number
): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError("userId and items are required", 400);
  }

  if (input.items.length === 0) {
    throw new ServiceError("Order must have at least one item", 400);
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = productList.find((p) => p.id === item.productId);
    if (!product) {
      throw new ServiceError(`Product ${item.productId} not found`, 400);
    }

    if (item.quantity <= 0) {
      throw new ServiceError("Quantity must be positive", 400);
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(`Insufficient stock for ${product.name}`, 400);
    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: nextId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orderList.push(order);

  return order;
}

export function updateOrderStatus(
  id: number,
  newStatus: string,
  orderList: Order[]
): Order {
  const order = orderList.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError("Order not found", 404);
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(newStatus)) {
    throw new ServiceError(
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      400
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(newStatus)) {
    throw new ServiceError(
      `Cannot transition from ${order.status} to ${newStatus}`,
      400
    );
  }

  order.status = newStatus as typeof order.status;

  return order;
}

