import { products } from "../data.js";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/product-service.js";
import { ServiceError } from "../services/errors.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const result = listProducts(
    {
      category: typeof category === "string" ? category : undefined,
      minPrice: typeof minPrice === "string" ? minPrice : undefined,
      maxPrice: typeof maxPrice === "string" ? maxPrice : undefined,
    },
    products
  );

  res.json(result);
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = getProductById(id, products);

  if (!product) {
    res.status(404).json({ error: "Product not found" });
    return;
  }

  res.json(product);
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body;

  try {
    const product = adjustProductStock(id, adjustment, products);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
    } else {
      throw err;
    }
  }
});

export { router as productRouter };

